import React from "react";

import JobDesc from "../components/Job/Desc";

const Work = ({ data: { workHistory }}) =>
<React.Fragment>
  {
    workHistory.edges.map(({ node }) =>
      <JobDesc {...node} />
    )
  }
</React.Fragment>

export default Work;

export const query = graphql`
  query workHistory {
    workHistory: allWorkJson {
      edges {
        node {
          project
          longName
          intro
          contribution
          links {
            url
            str
          }
        }
      }
    }
  }
`



