import React from "react";
import "./desc.scss";

const JobDesc = ({ project, longName, intro, contribution, links }) =>
<div className="workDesc">
  <h2 className="projectName">{project}</h2>
  {
    longName.length === 0 ? null :
    <h3 className="longName">{longName}</h3>
  }
  <hr className="projectUnderline" />

  <p className="projectIntro">{intro}</p>

  <h4 className="contribHeader">What I did</h4>
  {
    contribution.map(p =>
      <p className="contribItem">{p}</p>
    )
  }
  {
    links.length === 0 ? null :
    <React.Fragment>
      <h4 className="linksHeader">Links</h4>
      <ul className="projectLinks">
        {
          links.map(({ url, str }) =>
            <li className="prLink">
              <a href={url}>{str}</a>
            </li>
          )
        }
      </ul>
    </React.Fragment>
  }
</div>

export default JobDesc;



